parameters.jsCode:
const body = $input.first().json.body || $input.first().json;
const email = (body.email || '').toLowerCase().trim();
const name = body.name || '';
const source = body.source || 'unknown';
const productType = body.product_type || 'unknown';
const language = (body.language || 'EN').toUpperCase();

if (!email) {
  throw new Error('email is required');
}

// n8n Cloud denies $env access inside Code nodes ("access to env vars
// denied"), so the Brevo list/template IDs (already live, see
// docs/BREVO_LISTS_TAGS.md / docs/WELCOME_SEQUENCES.md) are hardcoded here.
const LIST_IDS = {
  'digital-products': 4,
  'ecom-merch': 5,
  'general-leads': 6,
  'vip': 7
};

function resolveListKey(source, productType) {
  const s = (source || '').toLowerCase();
  const p = (productType || '').toLowerCase();
  if (p.includes('gumroad') || p.includes('digital') || s.includes('gumroad') || s.includes('waitlist')) {
    return 'digital-products';
  }
  if (p.includes('merch') || p.includes('shop') || s.includes('shop') || s.includes('ecom')) {
    return 'ecom-merch';
  }
  return 'general-leads';
}

const listKey = resolveListKey(source, productType);
const listId = LIST_IDS[listKey];

// Welcome-sequence template per list + language, see docs/WELCOME_SEQUENCES.md
const TEMPLATE_IDS = {
  'digital-products': { DE: 1, EN: 2 },
  'ecom-merch': { DE: 9, EN: 10 },
  'general-leads': { DE: 0, EN: 0 }
};
const lang = (language === 'DE') ? 'DE' : 'EN';
const templateId = (TEMPLATE_IDS[listKey] || {})[lang] || 0;

return [{
  json: {
    email,
    name,
    source,
    productType,
    language: lang,
    listKey,
    listId,
    templateId
  }
}];

const data = $('Map Source -> List/Tags').item.json;
const entry = {
  timestamp: new Date().toISOString(),
  workflow: 'optin-to-brevo',
  email: data.email,
  source: data.source,
  productType: data.productType,
  language: data.language,
  list: data.listKey,
  listId: data.listId
};
// n8n Cloud has no host filesystem access; rely on this workflow's
// execution history (Executions tab) instead of writing to a local file.
return [{ json: entry }];

